from tests.studio_import_helper import load_studio_module




class _BlockStateStub:
    def __init__(self, blocked=False):
        self._blocked = bool(blocked)
        self.calls = []

    def blockSignals(self, blocked):
        previous = self._blocked
        self._blocked = bool(blocked)
        self.calls.append(bool(blocked))
        return previous

    def signalsBlocked(self):
        return self._blocked


class GuiStudioWorkerRegressionTest(unittest.TestCase):
    @classmethod
    def setUpClass(cls) -> None:
        cls.studio = load_studio_module(force_reload=True)
        cls.core = cls.studio.core

    def make_settings(self, target: str, **overrides):
        settings = {
            'target': target,
            'font_file': '',
            'width': 480,
            'height': 800,
            'font_size': 26,
            'ruby_size': 12,
            'line_spacing': 44,
            'margin_t': 12,
            'margin_b': 14,
            'margin_r': 12,
            'margin_l': 12,
            'dither': False,
            'threshold': 128,
            'night_mode': False,
            'kinsoku_mode': 'standard',
            'output_format': 'xtc',
            'output_conflict': 'rename',
            'output_name': '',
            'open_folder': False,
        }
        settings.update(overrides)
        return settings

    def test_wrapper_helpers_forward_to_worker_logic(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            base = Path(tmpdir)
            txt = base / 'sample.txt'
            txt.write_text('hello', encoding='utf-8')
            png = base / 'cover.png'
            png.write_bytes(b'png')
            doc = base / 'ignored.doc'
            doc.write_text('x', encoding='utf-8')

            args = self.studio.build_conversion_args(self.make_settings(str(txt), width=528, height=792, output_format='xtch'))
            self.assertEqual(args.width, 528)
            self.assertEqual(args.height, 792)
            self.assertEqual(args.output_format, 'xtch')

            targets = self.studio.resolve_supported_conversion_targets(base)
            self.assertIn(txt, targets)
            self.assertIn(png, targets)
            self.assertNotIn(doc, targets)

            self.assertEqual(self.studio.sanitize_output_stem('nested/name.txt'), 'name')
            summary, lines = self.studio.build_conversion_summary(2, 1, 0, [], False, skipped_count=1)
            self.assertIn('2 件', summary)
            self.assertTrue(lines)

    def test_right_preview_keeps_navigation_in_top_toggle_row(self):
        right_source = inspect.getsource(self.studio.MainWindow._build_right_preview)
        toggle_source = inspect.getsource(self.studio.MainWindow._build_view_toggle_bar)

        self.assertNotIn('lay.addWidget(self._build_nav_bar())', right_source)
        self.assertLess(
            right_source.index('lay.addWidget(self._build_view_toggle_bar())'),
            right_source.index('lay.addWidget(self.preview_stack, 1)'),
        )
        self.assertLess(
            toggle_source.index('top_lay.addWidget(self.view_help_btn)'),
            toggle_source.index('top_lay.addStretch(1)'),
        )
        self.assertLess(
            toggle_source.index('bottom_lay = QHBoxLayout()'),
            toggle_source.index('self._add_nav_controls_to_layout(bottom_lay, current_label_stretch=0)'),
        )
        self.assertLess(
            toggle_source.index('self._add_nav_controls_to_layout(bottom_lay, current_label_stretch=0)'),
            toggle_source.index('self._add_preview_zoom_controls_to_layout(bottom_lay, toggle_plan=toggle_plan)'),
        )
        self.assertLess(
            toggle_source.index('self._add_preview_zoom_controls_to_layout(bottom_lay, toggle_plan=toggle_plan)'),
            toggle_source.index('bottom_lay.addStretch(1)'),
        )

