    def test_bottom_panel_external_scroll_value_suppresses_signal_recursive_sync(self):
        source = inspect.getsource(self.studio.MainWindow._apply_bottom_panel_external_scroll_value)

        self.assertIn('self._bottom_panel_scrollbar_syncing = True', source)
        self.assertIn('source.setValue(int(value))', source)
        self.assertIn('finally:', source)
        self.assertIn('self._bottom_panel_scrollbar_syncing = False', source)
        self.assertEqual(source.count('self._sync_bottom_panel_external_scrollbar()'), 1)

    def test_bottom_panel_external_scroll_value_resyncs_after_set_value_failure(self):
        window = self.studio.MainWindow.__new__(self.studio.MainWindow)
        calls = []

        class _FailingScrollBar:
            def setValue(self, _value):
                raise RuntimeError('scroll failed')

        window._bottom_panel_scrollbar_syncing = False
        window._active_bottom_panel_scrollbar = lambda: _FailingScrollBar()
        window._sync_bottom_panel_external_scrollbar = lambda: calls.append(
            bool(getattr(window, '_bottom_panel_scrollbar_syncing', False))
        )

        window._apply_bottom_panel_external_scroll_value(12)

        self.assertEqual(calls, [False])
        self.assertFalse(window._bottom_panel_scrollbar_syncing)

