    def test_conversion_worker_wrapper_methods(self):
        worker = self.studio.ConversionWorker(self.make_settings('dummy'))
        self.assertEqual(worker._sanitize_output_stem('foo/bar.md'), 'bar')
        counts = worker._collect_conversion_counts(['a'], ['b'], [], [{'error': 'x'}], skipped=2)
        self.assertEqual(counts, {'converted': 1, 'renamed': 1, 'overwritten': 0, 'errors': 1, 'skipped': 2})
        target = worker._resolve_open_folder_target(Path('input.txt'), [Path('out/result.xtc')])
        self.assertEqual(target, Path('out'))

    def test_conversion_worker_stop_uses_event_flag(self):
        worker = self.studio.ConversionWorker(self.make_settings('dummy'))

        self.assertFalse(worker._is_stop_requested())
        self.assertTrue(hasattr(worker._stop_requested, 'is_set'))

        worker.stop()

        self.assertTrue(worker._is_stop_requested())
        self.assertTrue(worker._stop_requested.is_set())

    def test_bulk_block_signals_restores_previous_state(self):
        widget = _BlockStateStub(blocked=True)

        with self.studio._bulk_block_signals(widget):
            self.assertTrue(widget.signalsBlocked())

        self.assertTrue(widget.signalsBlocked())
        self.assertEqual(widget.calls, [True, True])

    def test_bulk_block_signals_handles_nested_contexts(self):
        widget = _BlockStateStub(blocked=False)

        with self.studio._bulk_block_signals(widget):
            self.assertTrue(widget.signalsBlocked())
            with self.studio._bulk_block_signals(widget):
                self.assertTrue(widget.signalsBlocked())
            self.assertTrue(widget.signalsBlocked())

        self.assertFalse(widget.signalsBlocked())
        self.assertEqual(widget.calls, [True, True, True, False])

    def test_emit_progress_normalizes_values(self):
        worker = self.studio.ConversionWorker(self.make_settings('dummy'))
        seen = []
        worker.progress.connect(lambda current, total, message: seen.append((current, total, message)))
        worker._emit_progress(9999, 0, None)
        self.assertEqual(seen, [(1, 1, '')])

    def test_emit_progress_normalizes_bytes_and_invalid_numbers(self):
        worker = self.studio.ConversionWorker(self.make_settings('dummy'))
        seen = []
        worker.progress.connect(lambda current, total, message: seen.append((current, total, message)))
        worker._emit_progress(' 2 ', b'4', '進行中'.encode('utf-8'))
        worker._emit_progress('bad', bytearray(b'   '), bytearray(' '.encode('utf-8')))
        self.assertEqual(seen, [(2, 4, '進行中'), (0, 1, '')])

