    def test_sync_results_selection_matches_paths_even_when_case_differs(self):
        user_role = self.studio.Qt.UserRole

        class _ResultItem:
            def __init__(self, path):
                self._path = path

            def data(self, role):
                return self._path if role == user_role else None

        class _ResultsList:
            def __init__(self, items):
                self._items = items
                self.current_item = None

            def count(self):
                return len(self._items)

            def item(self, idx):
                return self._items[idx]

            def setCurrentItem(self, item):
                self.current_item = item

            def clearSelection(self):
                self.current_item = None

            def setCurrentRow(self, idx):
                self.current_item = self._items[idx] if 0 <= idx < len(self._items) else None

            def row(self, item):
                return self._items.index(item)

        window = self.studio.MainWindow.__new__(self.studio.MainWindow)
        items = [_ResultItem('C:/Books/Result.XTC'), _ResultItem('D:/Other/Else.xtc')]
        results_list = _ResultsList(items)
        window.results_list = results_list
        with mock.patch.object(self.studio.os.path, 'normcase', side_effect=lambda value: str(value).replace('\\', '/').lower()):
            window._sync_results_selection_for_loaded_path('c:\\books\\result.xtc')
        self.assertIs(results_list.current_item, items[0])

