    def test_convert_warns_for_windows_like_duplicate_desired_paths_with_variant_strings(self):
        src1 = Path(r'C:/src/One.txt')
        src2 = Path(r'C:/src/Two.txt')
        worker = self.studio.ConversionWorker(self.make_settings(r'C:/src', open_folder=False, font_file='dummy.ttf'))

        log_messages = []
        worker.log.connect(log_messages.append)

        outputs = {
            src1: (Path(r'C:/out/same-1.xtc'), {'desired_path': r'C:\Out\same.xtc', 'final_path': r'C:\Out\same-1.xtc', 'renamed': True}),
            src2: (Path(r'C:/out/same.xtc'), {'desired_path': r'c:/out/sub/../same.xtc', 'final_path': r'c:/out/same.xtc'}),
        }

        with mock.patch.object(Path, 'exists', return_value=True),              mock.patch.object(worker, '_resolve_supported_targets', return_value=[src1, src2]),              mock.patch.object(self.studio.core, 'resolve_font_path', return_value='dummy.ttf'),              mock.patch.object(Path, 'is_file', return_value=False),              mock.patch.object(worker, '_output_path_for_target', side_effect=lambda path, *args, **kwargs: outputs[path]),              mock.patch.object(worker, '_process_target', side_effect=lambda path, *_args, **_kwargs: outputs[path][0]),              mock.patch.object(self.studio.worker_logic, '_bool_config_value', return_value=False):
            result = worker._convert()

        duplicate_warnings = [msg for msg in log_messages if '同じ出力名候補が複数入力で重複しました' in str(msg)]
        self.assertEqual(len(duplicate_warnings), 1)
        self.assertEqual(result['converted_files'], [str(Path(r'C:/out/same-1.xtc')), str(Path(r'C:/out/same.xtc'))])

    def test_convert_success_with_duplicate_plan_warning_and_skip(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            base = Path(tmpdir)
            src1 = base / 'a.txt'
            src2 = base / 'b.txt'
            src3 = base / 'c.txt'
            for path in (src1, src2, src3):
                path.write_text(path.stem, encoding='utf-8')
            font_path = base / 'dummy.ttf'
            font_path.write_text('font', encoding='utf-8')
            settings = self.make_settings(str(base), open_folder=False, font_file=str(font_path))
            worker = self.studio.ConversionWorker(settings)

            log_messages = []
            worker.log.connect(log_messages.append)

            outputs = {
                src1: (base / 'same-1.xtc', {'desired_path': str(base / 'same.xtc'), 'final_path': str(base / 'same-1.xtc'), 'renamed': True}),
                src2: (base / 'same.xtc', {'desired_path': str(base / 'same.xtc'), 'final_path': str(base / 'same.xtc'), 'overwritten': True}),
                src3: (None, None),
            }

            with mock.patch.object(worker, '_resolve_supported_targets', return_value=[src1, src2, src3]), \
                 mock.patch.object(self.studio.core, 'resolve_font_path', return_value=str(font_path)), \
                 mock.patch.object(worker, '_output_path_for_target', side_effect=lambda path, *args, **kwargs: outputs[path]), \
                 mock.patch.object(worker, '_process_target', side_effect=lambda path, font_value, args, out_path, progress_cb=None: out_path):
                result = worker._convert()

        self.assertEqual(result['converted_files'], [str(base / 'same-1.xtc'), str(base / 'same.xtc')])
        self.assertFalse(result['stopped'])
        self.assertEqual(result['errors'], [])
        self.assertEqual(result['skipped_count'], 1)
        joined = '\n'.join(log_messages)
        self.assertIn('自動連番で保存', joined)
        self.assertIn('上書き保存', joined)
        self.assertIn('同じ出力名候補が複数入力で重複しました', joined)
        self.assertIn('スキップ: c.txt', joined)

    def test_convert_does_not_count_renamed_or_overwritten_when_save_fails(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            base = Path(tmpdir)
            src1 = base / 'a.txt'
            src2 = base / 'b.txt'
            for path in (src1, src2):
                path.write_text(path.stem, encoding='utf-8')
            font_path = base / 'dummy.ttf'
            font_path.write_text('font', encoding='utf-8')
            worker = self.studio.ConversionWorker(self.make_settings(str(base), open_folder=False, font_file=str(font_path)))

            outputs = {
                src1: (base / 'same-1.xtc', {'desired_path': str(base / 'same.xtc'), 'final_path': str(base / 'same-1.xtc'), 'renamed': True}),
                src2: (base / 'same.xtc', {'desired_path': str(base / 'same.xtc'), 'final_path': str(base / 'same.xtc'), 'overwritten': True}),
            }

            def fake_process(path, font_value, args, out_path, progress_cb=None):
                raise RuntimeError(f'failed: {path.name}')

            with mock.patch.object(worker, '_resolve_supported_targets', return_value=[src1, src2]), \
                 mock.patch.object(self.studio.core, 'resolve_font_path', return_value=str(font_path)), \
                 mock.patch.object(worker, '_output_path_for_target', side_effect=lambda path, *args, **kwargs: outputs[path]), \
                 mock.patch.object(worker, '_process_target', side_effect=fake_process), \
                 mock.patch.object(self.studio.core, 'build_conversion_error_report', side_effect=lambda path, exc: {'headline': '保存失敗', 'display': f'エラー: {path.name}: {exc}'}):
                result = worker._convert()

        self.assertEqual(result['converted_files'], [])
        self.assertEqual(result['skipped_count'], 0)
        self.assertEqual(len(result['errors']), 2)
        self.assertEqual(result['message'], '変換できませんでした。(2 件エラー)')
        self.assertIn('自動連番 0 件', result['summary_lines'])
        self.assertIn('上書き 0 件', result['summary_lines'])

