    def test_convert_validates_target_and_font_path(self):
        worker = self.studio.ConversionWorker(self.make_settings(''))
        with self.assertRaisesRegex(RuntimeError, '変換対象ファイルまたはフォルダを指定してください'):
            worker._convert()

        missing_path = str(Path('missing-target.epub'))
        worker_missing = self.studio.ConversionWorker(self.make_settings(missing_path))
        with self.assertRaisesRegex(RuntimeError, '指定したパスが見つかりません'):
            worker_missing._convert()

        with tempfile.TemporaryDirectory() as tmpdir:
            src = Path(tmpdir) / 'book.epub'
            src.write_text('x', encoding='utf-8')
            worker_font = self.studio.ConversionWorker(self.make_settings(str(src), font_file='missing.ttf'))
            with mock.patch.object(worker_font, '_resolve_supported_targets', return_value=[src]), \
                 mock.patch.object(self.studio.core, 'resolve_font_path', return_value='missing.ttf'):
                with self.assertRaisesRegex(RuntimeError, 'フォントが見つかりません'):
                    worker_font._convert()

    def test_run_emits_finished_and_error_signals(self):
        worker = self.studio.ConversionWorker(self.make_settings('dummy'))
        finished_payloads = []
        error_messages = []
        worker.finished.connect(finished_payloads.append)
        worker.error.connect(error_messages.append)

        with mock.patch.object(worker, '_convert', return_value={'status': 'ok'}):
            worker.run()
        self.assertEqual(finished_payloads, [{'status': 'ok'}])
        self.assertEqual(error_messages, [])

        with mock.patch.object(worker, '_convert', side_effect=RuntimeError('boom')):
            worker.run()
        self.assertEqual(error_messages[-1], 'boom')



