class _ComboStub:
    def __init__(self, items=None, current_index=0):
        self.items = list(items or [])
        self._current_index = current_index
        self.blocked = []
        self.tooltip = ''

    def currentData(self):
        if 0 <= self._current_index < len(self.items):
            return self.items[self._current_index][1]
        return None

    def currentText(self):
        if 0 <= self._current_index < len(self.items):
            return self.items[self._current_index][0]
        return ''

    def currentIndex(self):
        return self._current_index

    def setCurrentIndex(self, index):
        self._current_index = index

    def itemData(self, index):
        return self.items[index][1] if 0 <= index < len(self.items) else None

    def itemText(self, index):
        return self.items[index][0] if 0 <= index < len(self.items) else ''

    def findData(self, data):
        for idx, (_text, item_data) in enumerate(self.items):
            if item_data == data:
                return idx
        return -1

    def findText(self, text):
        for idx, (item_text, _data) in enumerate(self.items):
            if item_text == text:
                return idx
        return -1

    def addItem(self, text, data=None):
        self.items.append((text, data))

    def clear(self):
        self.items.clear()
        self._current_index = -1

    def count(self):
        return len(self.items)

    def blockSignals(self, blocked):
        self.blocked.append(bool(blocked))

    def setToolTip(self, text):
        self.tooltip = text

    def model(self):
        return self

    def sort(self, _column):
        self.items.sort(key=lambda item: item[0])


class _SignalAwareComboStub(_ComboStub):
    def __init__(self, items=None, current_index=0, on_change=None):
        super().__init__(items=items, current_index=current_index)
        self.on_change = on_change
        self._signals_blocked = False

    def setCurrentIndex(self, index):
        self._current_index = index
        if not self._signals_blocked and callable(self.on_change):
            self.on_change()

    def blockSignals(self, blocked):
        super().blockSignals(blocked)
        self._signals_blocked = bool(blocked)


