class MainWindowLogicRegressionTest(unittest.TestCase):
    @classmethod
    def setUpClass(cls) -> None:
        cls.studio = load_studio_module()

    def make_window(self):
        return self.studio.MainWindow.__new__(self.studio.MainWindow)


    def test_load_xtc_from_bytes_preserves_previous_state_when_parse_fails(self):
        window = self.make_window()
        window.xtc_bytes = b'old-bytes'
        window.xtc_pages = ['old-pages']
        with mock.patch.object(self.studio, 'parse_xtc_pages', side_effect=RuntimeError('bad xtc')):
            with self.assertRaisesRegex(RuntimeError, 'bad xtc'):
                window.load_xtc_from_bytes(b'new-bytes')
        self.assertEqual(window.xtc_bytes, b'old-bytes')
        self.assertEqual(window.xtc_pages, ['old-pages'])

    def test_apply_loaded_xtc_document_sets_state_and_resets_page_input(self):
        window = self.make_window()
        window.page_input = _SpinStub(7)
        renders = []
        window.render_current_page = lambda *args, **kwargs: renders.append((window.xtc_bytes, list(window.xtc_pages), window.current_page_index, kwargs.get('refresh_navigation', True)))

        window._apply_loaded_xtc_document(b'new-bytes', ['page1', 'page2'])

        self.assertEqual(window.xtc_bytes, b'new-bytes')
        self.assertEqual(window.xtc_pages, ['page1', 'page2'])
        self.assertEqual(window.current_page_index, 0)
        self.assertEqual(window.page_input.range, (1, 2))
        self.assertEqual(window.page_input.value(), 1)
        self.assertEqual(renders, [(b'new-bytes', ['page1', 'page2'], 0, True)])

    def test_xtc_document_payload_normalizes_bytes_and_exposes_first_page(self):
        window = self.make_window()

        with mock.patch.object(self.studio, 'parse_xtc_pages', return_value=['page1', 'page2']):
            payload = window._xtc_document_payload(memoryview(b'abc'))

        self.assertEqual(payload['data'], b'abc')
        self.assertEqual(payload['pages'], ['page1', 'page2'])
        self.assertEqual(payload['total'], 2)
        self.assertEqual(payload['current_index'], 0)
        self.assertEqual(payload['current_page'], 1)

    def test_apply_xtc_document_payload_clamps_current_index_against_new_pages_not_previous_document(self):
        window = self.make_window()
