    def test_xtc_page_state_payload_clamps_index_and_exposes_current_page(self):
        window = self.make_window()
        page2 = types.SimpleNamespace(offset=2, length=3)
        window.xtc_pages = [
            types.SimpleNamespace(offset=0, length=2),
            page2,
            types.SimpleNamespace(offset=5, length=4),
        ]
        window.current_page_index = ' -4 '

        payload = window._xtc_page_state_payload()
        self.assertEqual(payload['total'], 3)
        self.assertEqual(payload['current_index'], 0)
        self.assertEqual(payload['current_page'], 1)
        self.assertIs(payload['page'], window.xtc_pages[0])

        payload = window._xtc_page_state_payload(' 99 ')
        self.assertEqual(payload['current_index'], 2)
        self.assertEqual(payload['current_page'], 3)
        self.assertIs(payload['page'], window.xtc_pages[2])

        payload = window._xtc_page_state_payload(1)
        self.assertEqual(payload['current_index'], 1)
        self.assertEqual(payload['current_page'], 2)
        self.assertIs(payload['page'], page2)


