    def test_set_current_page_index_clamps_and_optionally_refreshes_navigation(self):
        window = self.make_window()
        window.xtc_pages = ['p1', 'p2', 'p3']
        window.current_page_index = 1
        renders = []
        nav_updates = []
        window.render_current_page = lambda *args, **kwargs: (renders.append((window.current_page_index, kwargs.get('refresh_navigation', True))), kwargs.get('refresh_navigation', True) and window.update_navigation_ui())[0]
        window.update_navigation_ui = lambda: nav_updates.append(window.current_page_index)

        changed = window._set_current_page_index(' 99 ', refresh_navigation=True)

        self.assertTrue(changed)
        self.assertEqual(window.current_page_index, 2)
        self.assertEqual(renders, [(2, True)])
        self.assertEqual(nav_updates, [2])

        changed = window._set_current_page_index(2, refresh_navigation=True)

        self.assertFalse(changed)
        self.assertEqual(renders, [(2, True)])
        self.assertEqual(nav_updates, [2, 2])

        window.current_page_index = 1
        changed = window._set_current_page_index(0, refresh_navigation=False)

        self.assertTrue(changed)
        self.assertEqual(window.current_page_index, 0)
        self.assertEqual(renders[-1], (0, False))
        self.assertEqual(nav_updates, [2, 2])

    def test_change_page_uses_refresh_navigation_for_changed_pages(self):
        window = self.make_window()
        window.xtc_pages = ['p1', 'p2', 'p3']
        window.current_page_index = 0
        calls = []
        window._set_current_page_index = lambda index, refresh_navigation=False: calls.append((index, refresh_navigation)) or True

        window.change_page(' 2 ')

        self.assertEqual(calls, [(2, True)])

    def test_convert_no_supported_targets_mentions_images_in_error(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            src = Path(tmpdir) / 'empty'
            src.mkdir()
            font_path = Path(tmpdir) / 'dummy.ttf'
            font_path.write_text('font', encoding='utf-8')
            worker = self.studio.ConversionWorker({
                'target': str(src),
                'font_file': str(font_path),
                'font_size': 26, 'ruby_size': 12, 'line_spacing': 44,
                'margin_t': 12, 'margin_b': 14, 'margin_r': 12, 'margin_l': 12,
                'dither': False, 'threshold': 128, 'night_mode': False,
                'kinsoku_mode': 'standard', 'output_format': 'xtc',
                'output_conflict': 'rename', 'open_folder': False,
                'width': 480, 'height': 800,
            })
            with mock.patch.object(worker, '_resolve_supported_targets', return_value=[]):
                with self.assertRaisesRegex(RuntimeError, 'PNG / JPG / JPEG / WEBP'):
                    worker._convert()

