    def test_flush_pending_ui_changes_clears_focus_and_processes_events_only(self):
        window = self.make_window()
        call_order = []

        class _FocusStub:
            def clearFocus(self_nonlocal):
                call_order.append('clearFocus')

        class _InterpretSpinStub(_SpinStub):
            def interpretText(self_nonlocal):
                call_order.append('interpretText')

        window.font_size_spin = _InterpretSpinStub(26)
        sentinel = object()
        original_focus_widget = getattr(self.studio.QApplication, 'focusWidget', sentinel)
        original_process_events = getattr(self.studio.QApplication, 'processEvents', sentinel)
        self.studio.QApplication.focusWidget = staticmethod(lambda: _FocusStub())
        self.studio.QApplication.processEvents = staticmethod(lambda: call_order.append('processEvents'))
        try:
            window._flush_pending_ui_changes()
        finally:
            if original_focus_widget is sentinel:
                delattr(self.studio.QApplication, 'focusWidget')
            else:
                self.studio.QApplication.focusWidget = original_focus_widget
            if original_process_events is sentinel:
                delattr(self.studio.QApplication, 'processEvents')
            else:
                self.studio.QApplication.processEvents = original_process_events

        self.assertEqual(call_order, ['clearFocus', 'processEvents', 'processEvents'])
        self.assertNotIn('interpretText', call_order)

