    def test_close_event_ignores_when_thread_does_not_finish(self):
        window = self.make_window()
        window.worker = types.SimpleNamespace(stop=lambda: setattr(window, '_worker_stopped', True))

        class _BusyThread(_ThreadStub):
            def wait(self, timeout=None):
                self.wait_calls.append(timeout)
                return False

        thread = _BusyThread()
        window.worker_thread = thread
        window.save_ui_state = lambda: setattr(window, '_saved', True)
        event = _CloseEventStub()
        original_close = getattr(self.studio.QMainWindow, 'closeEvent', None)
        self.studio.QMainWindow.closeEvent = lambda _self, _event: setattr(window, '_super_called', True)
        messages = []
        try:
            with mock.patch.object(self.studio.QMessageBox, 'information', side_effect=lambda *args: messages.append(args[2]), create=True):
                window.closeEvent(event)
        finally:
            if original_close is None:
                delattr(self.studio.QMainWindow, 'closeEvent')
            else:
                self.studio.QMainWindow.closeEvent = original_close
        self.assertTrue(getattr(window, '_saved', False))
        self.assertTrue(getattr(window, '_worker_stopped', False))
        self.assertTrue(thread.quit_called)
        self.assertEqual(thread.wait_calls, [3000])
        self.assertTrue(event.ignored)
        self.assertFalse(getattr(window, '_super_called', False))
        self.assertTrue(messages)


