    def test_dispatchers_ignore_late_signals_after_finished_terminal_state(self):
        window = self.make_window()
        window._active_conversion_run_token = 7
        calls = {'finished': [], 'error': [], 'log': [], 'progress': []}
        window._append_log_with_status_fallback = lambda text, reflect_in_status=False: calls['log'].append(text) or True
        window._append_log_without_status = lambda _text: (_ for _ in ()).throw(AssertionError('legacy helper should not be used'))
        window.update_conversion_progress = lambda current, total, message: calls['progress'].append((current, total, message))
        original_finished = self.studio.MainWindow.on_conversion_finished.__get__(window, self.studio.MainWindow)
        original_error = self.studio.MainWindow.on_conversion_error.__get__(window, self.studio.MainWindow)
        window.on_conversion_finished = lambda result: (calls['finished'].append(result), original_finished(result))[1]
        window.on_conversion_error = lambda message: (calls['error'].append(message), original_error(message))[1]
        window._apply_conversion_terminal_state = lambda *args, **kwargs: None
        window._show_conversion_results = lambda *args, **kwargs: None
        window.statusBar = lambda: _StatusBarStub()
        window.progress_label = _LabelStub()
        window.busy_badge = _LabelStub()
        window.current_xtc_label = _LabelStub()
        window.results_summary_label = _LabelStub()
        window.results_list = _ListWidgetStub()
        window.bottom_tabs = _StackStub()
        window.log_edit = _TextAppendStub()
        window.progress_bar = _SpinStub(0)

        window._dispatch_conversion_finished(7, {'message': 'done'})
        window._dispatch_worker_log(7, 'late log')
        window._dispatch_conversion_progress(7, 1, 4, 'late progress')
        window._dispatch_conversion_error(7, 'late error')

        self.assertEqual(calls['finished'], [{'message': 'done'}])
        self.assertEqual(calls['error'], [])
        self.assertEqual(calls['log'], [])
        self.assertEqual(calls['progress'], [])
        self.assertEqual(window._active_conversion_run_token, 0)

