    def test_start_conversion_ignores_stale_worker_signals_after_replacement_run_starts(self):
        window = self.make_window()
        cfg = {'target': 'book.epub'}
        window._prepare_conversion_settings = lambda: cfg
        window._check_conversion_dependencies = lambda _cfg: True
        window.results_list = _ListWidgetStub()
        window.results_summary_label = _LabelStub()
        window.viewer_widget = _ViewerWidgetStub()
        window.current_xtc_label = _LabelStub()
        window.xtc_bytes = b'old'
        window.xtc_pages = ['p1']
        window.current_page_index = 1
        window.update_navigation_ui = lambda: None
        window.run_btn = _ButtonStub()
        window.stop_btn = _ButtonStub()
        window.progress_bar = _SpinStub(10)
        window.progress_label = _LabelStub()
        window.busy_badge = _LabelStub()
        window.log_edit = _TextAppendStub()
        window.current_output_format = lambda: 'xtc'
        window._supported_targets_for_path = lambda target: [Path('book.epub')]
        window.bottom_tabs = _StackStub()
        status = _StatusBarStub()
        window.statusBar = lambda: status

        class _SignalStub:
            def __init__(self):
                self.callbacks = []
            def connect(self, callback):
                self.callbacks.append(callback)
            def emit(self, *args, **kwargs):
                for callback in list(self.callbacks):
                    callback(*args, **kwargs)

        created_workers = []
        created_threads = []

        class _ThreadForStart:
            def __init__(self, *_args, **_kwargs):
                self.started = _SignalStub()
                self.finished = _SignalStub()
                self.deleted = False
                created_threads.append(self)
            def start(self):
                return None
            def quit(self, *_args, **_kwargs):
                return None
            def deleteLater(self):
                self.deleted = True

        class _WorkerForStart:
            def __init__(self, settings):
                self.settings = settings
                self.finished = _SignalStub()
                self.error = _SignalStub()
                self.log = _SignalStub()
                self.progress = _SignalStub()
                self.deleted = False
                created_workers.append(self)
            def moveToThread(self, thread):
                self.thread = thread
            def deleteLater(self, *_args, **_kwargs):
                self.deleted = True
            def run(self):
                return None

        with mock.patch.object(self.studio, 'QThread', _ThreadForStart), \
             mock.patch.object(self.studio, 'ConversionWorker', _WorkerForStart):
            window.start_conversion()
            old_worker = created_workers[-1]
            window.start_conversion()
            new_worker = created_workers[-1]

        calls = {'finished': [], 'error': [], 'log': [], 'progress': []}
        window.on_conversion_finished = lambda result: calls['finished'].append(result)
        window.on_conversion_error = lambda message: calls['error'].append(message)
        window._append_log_with_status_fallback = lambda text, reflect_in_status=False: calls['log'].append(text) or True
        window._append_log_without_status = lambda _text: (_ for _ in ()).throw(AssertionError('legacy helper should not be used'))
        window.append_log = lambda text: (_ for _ in ()).throw(RuntimeError(f'append_log should not be called: {text}'))
        window.update_conversion_progress = lambda current, total, message: calls['progress'].append((current, total, message))

        old_worker.finished.emit({'message': 'old done'})
        old_worker.error.emit('old error')
        old_worker.log.emit('old log')
        old_worker.progress.emit(1, 4, 'old progress')

        self.assertEqual(calls, {'finished': [], 'error': [], 'log': [], 'progress': []})

        new_worker.finished.emit({'message': 'new done'})
        new_worker.error.emit('new error')
        new_worker.log.emit('new log')
        new_worker.progress.emit(2, 4, 'new progress')

        self.assertEqual(calls['finished'], [{'message': 'new done'}])
        self.assertEqual(calls['error'], ['new error'])
        self.assertEqual(calls['log'], ['new log'])
        self.assertEqual(calls['progress'], [(2, 4, 'new progress')])


