    def test_emit_postprocess_warning_logs_and_deduplicates_status_message(self):
        window = self.make_window()
        status = _StatusBarStub()
        window.statusBar = lambda: status
        logs = []
        app_warnings = []
        window.append_log = lambda text, reflect_in_status=True: logs.append((text, reflect_in_status))
        status.showMessage('既存の警告', 5000)
        original_warning = self.studio.APP_LOGGER.warning
        self.studio.APP_LOGGER.warning = lambda fmt, *args: app_warnings.append(fmt % args if args else fmt)
        try:
            window._emit_postprocess_warning('既存の警告', duration_ms=3000)
            window._emit_postprocess_warning('  新しい警告  ', duration_ms=3000)
        finally:
            self.studio.APP_LOGGER.warning = original_warning

        self.assertEqual(logs, [('既存の警告', False), ('新しい警告', False)])
        self.assertEqual(app_warnings, ['非致命後処理警告: 既存の警告', '非致命後処理警告: 新しい警告'])
        self.assertEqual(status.messages[0], ('既存の警告', 5000))
        self.assertEqual(status.messages[-1], ('新しい警告', 3000))
        self.assertEqual(status.messages.count(('既存の警告', 3000)), 0)

