    def test_emit_unique_postprocess_warnings_with_fallback_deduplicates_already_emitted_messages(self):
        window = self.make_window()
        status = _StatusBarStub()
        window.statusBar = lambda: status
        emitted = []
        window._emit_postprocess_warnings_and_collect = (
            lambda warnings, duration_ms=5000, show_status=True: emitted.append((list(warnings), duration_ms, show_status)) or list(warnings)
        )

        already_emitted = {'警告A'}
        result = window._emit_unique_postprocess_warnings_with_fallback(
            ['警告A', '警告B', '警告C'],
            already_emitted,
            duration_ms=2900,
            show_status=False,
        )

        self.assertEqual(result, ['警告B', '警告C'])
        self.assertEqual(emitted, [(['警告B', '警告C'], 2900, False)])
        self.assertEqual(already_emitted, {'警告A', '警告B', '警告C'})

    def test_emit_unique_postprocess_warnings_or_append_to_log_retries_only_remaining_messages(self):
        window = self.make_window()
        status = _StatusBarStub()
        window.statusBar = lambda: status
        already_emitted: set[str] = set()
        batch_calls = []
        append_calls = []

        def emit_unique(warnings, emitted_messages=None, duration_ms=5000, show_status=True):
            batch_calls.append((list(warnings), duration_ms, show_status, set(emitted_messages or set())))
            if emitted_messages is not None:
                emitted_messages.add('警告A')
            return ['警告A']

        def append_unique(warnings, emitted_messages=None, allow_status_fallback=False, status_timeout_ms=5000):
            append_calls.append((list(warnings), allow_status_fallback, status_timeout_ms, set(emitted_messages or set())))
            if emitted_messages is not None:
                emitted_messages.add('警告B')
            return ['警告B']

        window._emit_unique_postprocess_warnings_with_fallback = emit_unique
        window._append_unique_postprocess_warnings_to_log_with_fallback = append_unique

        result = window._emit_unique_postprocess_warnings_or_append_to_log(
            ['警告A', '警告B'],
            already_emitted,
            duration_ms=3100,
            show_status=False,
        )

        self.assertEqual(result, ['警告A', '警告B'])
        self.assertEqual(batch_calls, [(['警告A', '警告B'], 3100, False, set())])
        self.assertEqual(append_calls, [(['警告A', '警告B'], False, 3100, {'警告A'})])
        self.assertEqual(already_emitted, {'警告A', '警告B'})



    def test_emit_unique_postprocess_warnings_or_append_to_log_shares_internal_emitted_set_when_argument_is_omitted(self):
        window = self.make_window()
