        window.bottom_tabs = _StackStub()
        helper_calls = []

        def staged_warning_helper(warning_values, emitted_messages=None, duration_ms=5000, show_status=True):
            normalized = tuple(self.studio.worker_logic.coerce_postprocess_warning_messages(warning_values))
            helper_calls.append(normalized)
            if len(helper_calls) == 1:
                return []
            return list(normalized)

        window._emit_unique_postprocess_warnings_or_append_to_log = staged_warning_helper

        window.on_conversion_finished({
            'message': 'done',
            'converted_files': ['exports/book.xtc'],
            'summary_lines': ['保存 1 件'],
            'stopped': False,
        })

        self.assertGreaterEqual(len(helper_calls), 2)
        self.assertEqual(helper_calls[0], ('変換結果表示エラー: result panel boom',))
        self.assertIn(('変換結果表示エラー: result panel boom',), helper_calls[1:])

