    def test_manual_refresh_preview_normalizes_boolean_like_refresh_context_flags(self):
        window = self.make_window()
        calls = []
        window._flush_pending_ui_changes = lambda: calls.append(('flush', None))
        window.current_output_format = lambda: 'xtch'
        window._current_preview_payload = lambda: {'mode': 'text', 'output_format': 'xtc', 'max_pages': 10}
        window.request_preview_refresh = lambda **kwargs: calls.append(('refresh', kwargs))
        window._update_top_status = lambda: calls.append(('status', None))
        window.save_ui_state = lambda: calls.append(('save', None))

        original_builder = self.studio.preview_controller.build_manual_preview_refresh_context
        self.studio.preview_controller.build_manual_preview_refresh_context = lambda *args, **kwargs: {
            'reset_page': 'false',
            'preview_payload': 'not-a-mapping',
            'should_update_top_status': 'false',
            'should_save_ui_state': '1',
        }
        try:
            window.manual_refresh_preview()
        finally:
            self.studio.preview_controller.build_manual_preview_refresh_context = original_builder

        self.assertEqual(calls[0], ('flush', None))
        self.assertEqual(calls[1][0], 'refresh')
        self.assertEqual(calls[1][1], {
            'reset_page': False,
            'preview_payload': {},
        })
        self.assertEqual(calls[2:], [('save', None)])


