    def test_render_current_preview_page_reuses_cached_pixmap_for_same_page(self):
        window = self.make_window()
        window.preview_label = _LabelStub()
        window.preview_pages_b64 = ['QUJD']
        window.current_preview_page_index = 0
        window._font_preview_target_size = lambda: _SizeCarrier(480, 720)

        class _QImageStub:
            def isNull(self):
                return False

        class _QPixmapStub:
            def isNull(self):
                return False

            def scaled(self, _target, _aspect, _transform):
                return _PixmapResult(300, 500)

        pixmap = _QPixmapStub()
        with mock.patch.object(self.studio.base64, 'b64decode', return_value=b'data') as mocked_b64:
            with mock.patch.object(self.studio.QImage, 'fromData', return_value=_QImageStub(), create=True) as mocked_from_data:
                with mock.patch.object(self.studio.QPixmap, 'fromImage', return_value=pixmap, create=True) as mocked_from_image:
                    window.render_current_preview_page()
                    window.render_current_preview_page()

        self.assertIsNotNone(window.preview_label.pixmap)
        self.assertEqual(mocked_b64.call_count, 1)
        self.assertEqual(mocked_from_data.call_count, 1)
        self.assertEqual(mocked_from_image.call_count, 1)

    def test_render_current_preview_page_reuses_cached_pixmap_when_returning_to_previous_page(self):
        window = self.make_window()
        window.preview_label = _LabelStub()
        window.preview_pages_b64 = ['QUJD', 'REVG']
        window.current_preview_page_index = 0
        window._font_preview_target_size = lambda: _SizeCarrier(480, 720)

        class _QImageStub:
            def isNull(self):
                return False

        class _QPixmapStub:
            def __init__(self, width, height):
                self._width = width
                self._height = height

            def isNull(self):
                return False

            def scaled(self, _target, _aspect, _transform):
                return _PixmapResult(self._width, self._height)

        pixmaps = [_QPixmapStub(300, 500), _QPixmapStub(310, 510)]
        with mock.patch.object(self.studio.base64, 'b64decode', return_value=b'data') as mocked_b64:
            with mock.patch.object(self.studio.QImage, 'fromData', side_effect=[_QImageStub(), _QImageStub()], create=True) as mocked_from_data:
                with mock.patch.object(self.studio.QPixmap, 'fromImage', side_effect=pixmaps, create=True) as mocked_from_image:
                    window.render_current_preview_page()
                    window.current_preview_page_index = 1
                    window.render_current_preview_page()
                    window.current_preview_page_index = 0
                    window.render_current_preview_page()

        self.assertEqual(mocked_b64.call_count, 2)
        self.assertEqual(mocked_from_data.call_count, 2)
        self.assertEqual(mocked_from_image.call_count, 2)

