    def test_cleanup_worker_does_not_clear_replacement_worker_objects(self):
        window = self.make_window()
        window.run_btn = _ButtonStub()
        window.stop_btn = _ButtonStub()
        window.run_btn.setEnabled(False)
        window.stop_btn.setEnabled(True)

        class _Deletable:
            def __init__(self):
                self.deleted = False
            def deleteLater(self):
                self.deleted = True

        old_worker = _Deletable()
        old_thread = _Deletable()
        new_worker = _Deletable()
        new_thread = _Deletable()
        window.worker = new_worker
        window.worker_thread = new_thread

        window.cleanup_worker(expected_worker=old_worker, expected_thread=old_thread)

        self.assertTrue(old_worker.deleted)
        self.assertTrue(old_thread.deleted)
        self.assertFalse(new_worker.deleted)
        self.assertFalse(new_thread.deleted)
        self.assertIs(window.worker, new_worker)
        self.assertIs(window.worker_thread, new_thread)
        self.assertFalse(window.run_btn.enabled)
        self.assertTrue(window.stop_btn.enabled)


    def test_cleanup_worker_ignores_worker_control_reset_failure_after_clearing_refs(self):
        window = self.make_window()

        class _Deletable:
            def __init__(self):
                self.deleted = False
            def deleteLater(self):
                self.deleted = True

        worker = _Deletable()
        thread = _Deletable()
        window.worker = worker
        window.worker_thread = thread
        window._set_worker_controls_running = mock.Mock(side_effect=RuntimeError('ui reset failed'))

        window.cleanup_worker()

        self.assertTrue(worker.deleted)
        self.assertTrue(thread.deleted)
        self.assertIsNone(window.worker)
        self.assertIsNone(window.worker_thread)
