    def test_cleanup_worker_ignores_already_deleted_qobject_wrappers(self):
        window = self.make_window()

        class _DeletedWrapper:
            @property
            def deleteLater(self):
                raise RuntimeError('Internal C++ object already deleted')

        thread = types.SimpleNamespace(deleteLater=lambda: setattr(window, '_thread_deleted', True))
        window.worker = _DeletedWrapper()
        window.worker_thread = thread
        window.run_btn = _ButtonStub()
        window.stop_btn = _ButtonStub()

        window.cleanup_worker()

        self.assertIsNone(window.worker)
        self.assertIsNone(window.worker_thread)
        self.assertTrue(getattr(window, '_thread_deleted', False))
        self.assertTrue(window.run_btn.enabled)
        self.assertFalse(window.stop_btn.enabled)

    def test_request_preview_refresh_flushes_pending_ui_changes_before_collecting_payload(self):
        window = self.make_window()
        window.preview_label = _LabelStub()
        window.preview_update_btn = _ButtonStub()
        window.preview_status_label = _LabelStub()
        window.preview_page_limit_spin = _SpinStub(10)
        window.viewer_widget = _ViewerWidgetStub()
        window.current_preview_page_index = 0
        window.current_page_index = 0
        window.current_device_preview_page_index = 0
        window._update_top_status = lambda: None
        window._set_current_xtc_display_name = lambda name: setattr(window, '_display_name', name)
        window._font_preview_target_size = lambda: self.studio.QSize(320, 480)
        window.current_preview_mode = 'text'
        window.preview_image_data_url = None
        window.target_edit = _LineEditStub('book.epub')
        window.current_font_value = lambda: 'font.ttf'

        class _PendingSpinStub(_SpinStub):
            def __init__(self, value=0, pending=None):
                super().__init__(value)
                self.pending = pending

            def interpretText(self):
                if self.pending is not None:
                    self._value = self.pending

            def clearFocus(self):
                self.interpretText()

        window.font_size_spin = _PendingSpinStub(26, pending=31)
        window.ruby_size_spin = _SpinStub(14)
        window.line_spacing_spin = _SpinStub(46)
        window.margin_t_spin = _SpinStub(10)
        window.margin_b_spin = _SpinStub(11)
        window.margin_r_spin = _SpinStub(12)
        window.margin_l_spin = _SpinStub(13)
        window.dither_check = _CheckStub(False)
        window.threshold_spin = _SpinStub(128)
        window.night_check = _CheckStub(False)
        window.current_kinsoku_mode = lambda: 'standard'
        window.current_output_format = lambda: 'xtch'
        window.width_spin = _SpinStub(600)
        window.height_spin = _SpinStub(800)
        captured = {}

        def _fake_generate_preview_bundle(payload, progress_cb=None):
            captured.update(dict(payload))
            return {'pages': ['ZmFrZQ=='], 'truncated': False, 'source_count': 1}

        sentinel = object()
        original_focus_widget = getattr(self.studio.QApplication, 'focusWidget', sentinel)
        try:
            self.studio.QApplication.focusWidget = staticmethod(lambda: window.font_size_spin)
            with mock.patch.object(self.studio.core, 'generate_preview_bundle', side_effect=_fake_generate_preview_bundle), \
                 mock.patch.object(self.studio, 'QPixmap', _PixmapStub), \
                 mock.patch.object(self.studio, 'QImage', _ImageStub):
                result = window.request_preview_refresh(reset_page=False)
        finally:
            if original_focus_widget is sentinel:
                delattr(self.studio.QApplication, 'focusWidget')
            else:
                self.studio.QApplication.focusWidget = original_focus_widget

        self.assertTrue(result)
        self.assertEqual(captured.get('font_size'), 31)

