    def test_window_state_save_payload_collects_geometry_splitter_and_pending_width(self):
        window = self.make_window()
        window.isMaximized = lambda: False
        geom = types.SimpleNamespace(width=lambda: 1200, height=lambda: 800)
        window.geometry = lambda: geom
        window.normalGeometry = lambda: types.SimpleNamespace(width=lambda: 900, height=lambda: 700)
        window.saveGeometry = lambda: b'geom'
        window.main_splitter = types.SimpleNamespace(sizes=lambda: [0, 700])
        window.left_splitter = types.SimpleNamespace(saveState=lambda: b'split', sizes=lambda: [310, 210])
        window.left_panel = _PanelStub(False)
        window._pending_left_panel_width = 512

        payload = window._window_state_save_payload()

        self.assertEqual(payload['geometry'], b'geom')
        self.assertEqual((payload['window_width'], payload['window_height']), (1200, 800))
        self.assertFalse(payload['is_maximized'])
        self.assertEqual(payload['left_panel_width'], 512)
        self.assertEqual(payload['left_splitter_state'], b'split')
        self.assertEqual(payload['left_splitter_top'], 310)
        self.assertEqual(payload['left_splitter_bottom'], 210)
        self.assertFalse(payload['left_panel_visible'])

