    def test_supported_targets_and_default_output_name_helpers(self):
        window = self.make_window()
        with tempfile.TemporaryDirectory() as tmpdir:
            base = Path(tmpdir)
            src = base / 'book.epub'
            src.write_text('x', encoding='utf-8')
            with mock.patch.object(self.studio.ConversionWorker, '_resolve_supported_targets', return_value=[src]):
                self.assertEqual(window._supported_targets_for_path(str(src)), [src])
            self.assertEqual(window._supported_targets_for_path(''), [])
            self.assertEqual(window._supported_targets_for_path(str(base / 'missing.epub')), [])

            window.current_output_format = lambda: 'xtch'
            with mock.patch.object(self.studio.core, 'get_output_path_for_target', return_value=base / 'out.xtch'):
                self.assertEqual(window._default_output_name_for_target(src), 'out')
            with mock.patch.object(self.studio.core, 'get_output_path_for_target', return_value=None):
                self.assertEqual(window._default_output_name_for_target(src), 'book')

