    def test_init_logs_session_path_without_status_reflection(self):
        original_build_ui = self.studio.MainWindow._build_ui
        original_apply_styles = self.studio.MainWindow._apply_styles
        original_restore_settings = self.studio.MainWindow._restore_settings
        original_setup_shortcuts = self.studio.MainWindow._setup_global_navigation_shortcuts
        original_load_preset_definitions = self.studio.MainWindow._load_preset_definitions

        session_logs = []
        app_stub = types.SimpleNamespace(installEventFilter=lambda _obj: None)

        def fake_build_ui(window):
            window.log_edit = _TextAppendStub()
            window.progress_label = _LabelStub()
            window.statusBar = lambda: _StatusBarStub()
            window._append_log_with_status_fallback = lambda text, reflect_in_status=False: session_logs.append((text, reflect_in_status)) or True

        self.studio.MainWindow._build_ui = fake_build_ui
        self.studio.MainWindow._apply_styles = lambda _window: None
        self.studio.MainWindow._restore_settings = lambda _window: None
        self.studio.MainWindow._setup_global_navigation_shortcuts = lambda _window: None
        self.studio.MainWindow._load_preset_definitions = lambda _window: {}
        with mock.patch.object(self.studio.QApplication, 'instance', return_value=app_stub, create=True):
            try:
                window = self.studio.MainWindow()
            finally:
                self.studio.MainWindow._build_ui = original_build_ui
                self.studio.MainWindow._apply_styles = original_apply_styles
                self.studio.MainWindow._restore_settings = original_restore_settings
                self.studio.MainWindow._setup_global_navigation_shortcuts = original_setup_shortcuts
                self.studio.MainWindow._load_preset_definitions = original_load_preset_definitions

        self.assertIsNotNone(window)
        self.assertTrue(session_logs)
        self.assertTrue(session_logs[0][0].startswith('ログ保存先: '))

    def test_log_optional_dependency_status_and_dependency_check(self):
        window = self.make_window()
        seen_logs = []
        window._append_log_with_status_fallback = lambda text, reflect_in_status=False: seen_logs.append((text, reflect_in_status)) or True
        with mock.patch.object(self.studio.core, 'list_optional_dependency_status', return_value=[
            {'label': 'ebooklib', 'purpose': 'EPUB 変換', 'impact': 'feature', 'available': False},
            {'label': 'numpy', 'purpose': 'XTC / XTCH pack 高速化', 'impact': 'performance', 'available': False},
            {'label': 'tqdm', 'purpose': '進捗表示', 'impact': 'convenience', 'available': False},
            {'label': 'bs4', 'purpose': 'HTML 解析', 'impact': 'feature', 'available': True},
        ]):
            window._log_optional_dependency_status()
        self.assertIn('ebooklib', seen_logs[0][0])
        self.assertIn('numpy', seen_logs[0][0])
        self.assertIn('tqdm', seen_logs[0][0])
        self.assertIn('高速化用の追加ライブラリ', seen_logs[0][0])

        window2 = self.make_window()
        window2._append_log_with_status_fallback = lambda text, reflect_in_status=False: seen_logs.append((text, reflect_in_status)) or True
        with mock.patch.object(self.studio.core, 'list_optional_dependency_status', return_value=[]):
            window2._log_optional_dependency_status()

        window._supported_targets_for_path = lambda target: [Path('book.epub')]
        window._missing_dependencies_for_targets = lambda targets: [{'label': 'ebooklib', 'package': 'ebooklib', 'purpose': 'EPUB 変換'}]
        warnings = []
        with mock.patch.object(self.studio.QMessageBox, 'warning', side_effect=lambda *args: warnings.append(args)):
            ok = window._check_conversion_dependencies({'target': 'book.epub'})
        self.assertFalse(ok)
        self.assertTrue(warnings)
        self.assertIn('ebooklib', seen_logs[-1][0])

        window._missing_dependencies_for_targets = lambda targets: []
        self.assertTrue(window._check_conversion_dependencies({'target': 'book.epub'}))

    def test_check_conversion_dependencies_falls_back_to_status_bar_when_warning_dialog_raises(self):
        window = self.make_window()
        status_bar = _StatusBarStub()
        window.statusBar = lambda: status_bar
        window._supported_targets_for_path = lambda target: [Path('book.epub')]
        window._missing_dependencies_for_targets = lambda targets: [{'label': 'ebooklib', 'package': 'ebooklib', 'purpose': 'EPUB 変換'}]
        seen_logs = []
        window._append_log_with_status_fallback = None
        window._append_log_without_status = seen_logs.append

        with mock.patch.object(self.studio.QMessageBox, 'warning', side_effect=RuntimeError('dialog failed'), create=True):
            ok = window._check_conversion_dependencies({'target': 'book.epub'})

        self.assertFalse(ok)
