    def test_display_settings_popup_exposes_panel_button_toggle(self):
        window = self.make_window()
        window.current_ui_theme = 'light'
        window.open_folder_check = _CheckStub(True)
        window.panel_button_visible = False
        window.output_conflict_combo = _ComboStub([('リネーム', 'rename'), ('上書き', 'overwrite')], current_index=0)
        window.current_output_conflict_mode = lambda: 'rename'
        visible_calls = []
        window.set_panel_button_visible = lambda visible: visible_calls.append(bool(visible))
        window.settings_btn = types.SimpleNamespace(
            mapToGlobal=lambda _pt: types.SimpleNamespace(x=lambda: 40, y=lambda: 24),
            width=lambda: 20,
            height=lambda: 20,
        )
        window.screen = lambda: None

        class _Signal:
            def __init__(self):
                self._callbacks = []

            def connect(self, callback):
                self._callbacks.append(callback)

            def emit(self, *args, **kwargs):
                for callback in list(self._callbacks):
                    callback(*args, **kwargs)

        class _Action:
            def __init__(self, text=''):
                self.text = text
                self.checkable = False
                self.checked = False
                self.toggled = _Signal()
                self.triggered = _Signal()

            def setCheckable(self, value):
                self.checkable = bool(value)

            def setChecked(self, value):
                self.checked = bool(value)

        class _Menu:
            instances = []

            def __init__(self, *_args, **_kwargs):
                self.actions = []
                self.menus = []
                type(self).instances.append(self)

            def setObjectName(self, _name):
                pass

            def setToolTipsVisible(self, _visible):
                pass

            def addSection(self, _title):
                pass

            def addSeparator(self):
                pass

            def addAction(self, text):
                action = _Action(text)
                self.actions.append(action)
                return action

            def addMenu(self, text):
                menu = _Menu()
                menu.title = text
                self.menus.append(menu)
                return menu

            def sizeHint(self):
                return types.SimpleNamespace(width=lambda: 120, height=lambda: 80)

            def exec(self, _point):
                pass

        class _ActionGroup:
            def __init__(self, *_args, **_kwargs):
                self.actions = []

            def setExclusive(self, _value):
                pass

            def addAction(self, action):
                self.actions.append(action)

        with mock.patch.object(self.studio, 'QMenu', _Menu), mock.patch.object(self.studio, 'QActionGroup', _ActionGroup):
            window.show_display_settings_popup()

        top_menu = _Menu.instances[0]
        panel_actions = [action for action in top_menu.actions if action.text == '三本線ボタンを表示']
        self.assertEqual(len(panel_actions), 1)
        panel_action = panel_actions[0]
        self.assertTrue(panel_action.checkable)
        self.assertFalse(panel_action.checked)

        panel_action.toggled.emit(True)
        self.assertEqual(visible_calls, [True])

        window = self.make_window()
        window._initialized = True
        window.left_panel = _PanelStub(False)
        window._pending_left_panel_width = 512
        window.main_splitter = types.SimpleNamespace(sizes=lambda: [0, 700])
        window.left_splitter = types.SimpleNamespace(saveState=lambda: b'state', sizes=lambda: [300, 200])
        window.bottom_tabs = types.SimpleNamespace(currentIndex=lambda: 1)
        window.settings_store = _SettingsStoreStub()
        window.isMaximized = lambda: False
        window.saveGeometry = lambda: b'geom'
        geom = types.SimpleNamespace(width=lambda: 1200, height=lambda: 800)
        window.geometry = lambda: geom
        window.normalGeometry = lambda: geom
        window.current_ui_theme = 'light'
        window.panel_button_visible = True
        window._nav_reversed = False
        window.actual_size_check = _CheckStub(False)
        window.calib_spin = _SpinStub(100)
        window.page_input = _SpinStub(1)
        window.target_edit = _LineEditStub('book.epub')
        window.output_format_combo = _ComboStub([('XTC', 'xtc')], current_index=0)
        window.preset_combo = _ComboStub([('Preset', 'preset1')], current_index=0)
        window.save_ui_state()
        self.assertIn(('left_panel_width', 512), window.settings_store.set_calls)


