    def test_current_preview_payload_uses_render_settings_base(self):
        window = self.make_window()
        window.current_preview_mode = 'image'
        window.preview_image_data_url = b'  data:image/png;base64,QUJD  '
        window._current_render_settings_base = lambda: {
            'target': 'book.epub',
            'font_file': 'font.ttf',
            'font_size': 26,
            'ruby_size': 12,
            'line_spacing': 44,
            'margin_t': 10,
            'margin_b': 11,
            'margin_r': 12,
            'margin_l': 13,
            'dither': True,
            'threshold': 144,
            'night_mode': False,
            'kinsoku_mode': 'standard',
            'output_format': 'xtch',
            'width': 600,
            'height': 800,
        }

        payload = window._current_preview_payload()

        # A normal target path should take priority over stale image-preview state.
        # This keeps EPUB/TXT/Markdown previews rendered from the selected target
        # instead of accidentally reusing the previous image data URL.
        self.assertEqual(payload['mode'], 'text')
        self.assertEqual(payload['file_b64'], '')
        self.assertEqual(payload['target_path'], 'book.epub')
        self.assertEqual(payload['font_file'], 'font.ttf')
        self.assertEqual(payload['output_format'], 'xtch')
        self.assertEqual(payload['dither'], 'true')
        self.assertEqual(payload['night_mode'], 'false')
        self.assertEqual((payload['width'], payload['height']), (600, 800))

