        window.update_navigation_ui = lambda: None
        window._normalized_xtc_page_index = lambda index, total: 0

        applied_profiles = []
        original_set_profile = window.viewer_widget.set_profile
        def _record_profile(profile):
            applied_profiles.append(profile.key)
            original_set_profile(profile)
        window.viewer_widget.set_profile = _record_profile

        class _QImageStub:
            def __init__(self, width, height):
                self._width = width
                self._height = height
            def isNull(self):
                return False
            def width(self):
                return self._width
            def height(self):
                return self._height

        with mock.patch.object(self.studio.base64, 'b64decode', return_value=b'data'):
            with mock.patch.object(self.studio.QImage, 'fromData', return_value=_QImageStub(528, 792), create=True):
                window.render_current_page(refresh_navigation=False)

        self.assertGreaterEqual(len(applied_profiles), 2)
        self.assertEqual(applied_profiles[0], 'x3')
        self.assertEqual(applied_profiles[-1], 'x3')
        self.assertEqual(window.viewer_widget.profile.key, 'x3')
        self.assertEqual((window.viewer_widget.profile.width_px, window.viewer_widget.profile.height_px), (528, 792))

