    def test_preset_and_font_helpers(self):
        window = self.make_window()
        window.preset_combo = _ComboStub([('プリセット1', 'preset_1'), ('プリセット2', None)], current_index=0)
        self.assertEqual(window.selected_preset_key(), 'preset_1')
        window.preset_combo = _ComboStub([('プリセット 2', None)], current_index=0)
        self.assertEqual(window.selected_preset_key(), 'preset_2')
        window.preset_combo = _ComboStub([], current_index=-1)
        self.assertIsNone(window.selected_preset_key())

        class _ContainsSettings(_SettingsStoreStub):
            def contains(self, key):
                return key in self.values

        window = self.make_window()
        window.settings_store = _ContainsSettings({
            'font_file': 'stored-font.ttf',
            'night_mode': True,
            'dither': True,
            'kinsoku_mode': 'bad',
            'presets/preset_1/font_size': 33,
        })
        window._default_font_name = lambda: 'default-font.ttf'
        presets = window._load_preset_definitions()
        self.assertEqual(presets['preset_1']['font_size'], 33)
        self.assertTrue(presets['preset_1']['font_file'])
        self.assertEqual(presets['preset_1']['kinsoku_mode'], 'standard')

        window.settings_store = _ContainsSettings({
            'font_file': 'stored-font.ttf',
            'night_mode': False,
            'dither': False,
            'presets/preset_1/night_mode': 'false',
            'presets/preset_1/dither': '0',
        })
        presets = window._load_preset_definitions()
        self.assertFalse(presets['preset_1']['night_mode'])
        self.assertFalse(presets['preset_1']['dither'])

        window.settings_store = _ContainsSettings({
            'font_file': 'stored-font.ttf',
            'presets/preset_1/font_file': 'C:/Windows/Fonts/msgothic.ttc',
        })
        presets = window._load_preset_definitions()
        self.assertEqual(presets['preset_1']['font_file'], 'stored-font.ttf')

        window.settings_store = _ContainsSettings({
            'font_file': 'stored-font.ttf',
            'presets/preset_1/profile': 'x4',
            'presets/preset_1/width': 999,
            'presets/preset_1/height': 1111,
            'presets/preset_1/output_format': 'BROKEN',
        })
        presets = window._load_preset_definitions()
        self.assertEqual(presets['preset_1']['width'], self.studio.DEVICE_PROFILES['x4'].width_px)
        self.assertEqual(presets['preset_1']['height'], self.studio.DEVICE_PROFILES['x4'].height_px)
        self.assertEqual(presets['preset_1']['output_format'], 'xtc')

        self.assertEqual(window._preset_display_name({'button_text': 'ボタン', 'name': '名前'}), 'ボタン / 名前')
        with mock.patch.object(self.studio.core, 'describe_font_value', return_value='Font Label'):
            summary = window._preset_summary_text({
                'button_text': 'プリセット1', 'name': '名前', 'font_file': 'font.ttf', 'night_mode': True,
                'dither': False, 'profile': 'x4', 'kinsoku_mode': 'simple', 'output_format': 'xtch',
                'font_size': 28, 'ruby_size': 12, 'line_spacing': 44,
                'margin_t': 10, 'margin_b': 11, 'margin_r': 12, 'margin_l': 13,
            })
        self.assertIn('Font Label', summary)
        self.assertIn('出力形式: XTCH', summary)
        self.assertIn('白黒反転: ON', summary)
        self.assertNotIn('波線描画:', summary)
        self.assertNotIn('波線位置:', summary)
        with mock.patch.object(self.studio.core, 'describe_font_value', return_value='Font Label'):
            summary_false = window._preset_summary_text({
                'button_text': 'プリセット1', 'name': '名前', 'font_file': 'font.ttf', 'night_mode': 'false',
                'dither': '0', 'profile': 'x4', 'kinsoku_mode': 'simple', 'output_format': 'xtch',
                'font_size': 28, 'ruby_size': 12, 'line_spacing': 44,
                'margin_t': 10, 'margin_b': 11, 'margin_r': 12, 'margin_l': 13,
            })
        self.assertIn('白黒反転: OFF', summary_false)
        self.assertIn('ディザ: OFF', summary_false)
        self.assertNotIn('波線描画:', summary_false)
        self.assertNotIn('波線位置:', summary_false)
        with mock.patch.object(self.studio.core, 'describe_font_value', return_value='Font Label'):
            summary_broken = window._preset_summary_text({
                'button_text': 'プリセット1', 'name': '名前', 'font_file': 'font.ttf', 'night_mode': 'false',
                'dither': '0', 'profile': 'broken', 'kinsoku_mode': 'broken', 'output_format': 'broken',
                'font_size': 'bad', 'ruby_size': None, 'line_spacing': '',
                'margin_t': 'x', 'margin_b': '14', 'margin_r': {}, 'margin_l': [],
            })
        self.assertIn('機種: X4', summary_broken)
        self.assertIn('本文: 26', summary_broken)
        self.assertIn('ルビ: 12', summary_broken)
        self.assertNotIn('波線描画:', summary_broken)
        self.assertNotIn('波線位置:', summary_broken)


    def test_preset_summary_plain_text_omits_html_tags(self):
        window = self.make_window()
        with mock.patch.object(self.studio.core, 'describe_font_value', return_value='Font Label'):
            summary = window._preset_summary_plain_text({
                'button_text': 'プリセット1', 'name': '名前', 'font_file': 'font.ttf', 'night_mode': True,
                'dither': False, 'profile': 'x4', 'kinsoku_mode': 'simple', 'output_format': 'xtch',
                'font_size': 28, 'ruby_size': 12, 'line_spacing': 44,
                'margin_t': 10, 'margin_b': 11, 'margin_r': 12, 'margin_l': 13,
            })
        self.assertIn('Font Label', summary)
        self.assertIn('出力形式: XTCH', summary)
        self.assertNotIn('波線描画:', summary)
        self.assertNotIn('波線位置:', summary)
        self.assertNotIn('<div', summary)
        self.assertEqual(summary.count('\n'), 3)

        window = self.make_window()
        window.preset_definitions = {'preset_1': {'button_text': 'プリセット1', 'name': 'P1', 'font_size': 28, 'ruby_size': 12, 'line_spacing': 44, 'margin_t': 10, 'margin_b': 11, 'margin_r': 12, 'margin_l': 13, 'font_file': 'font.ttf', 'night_mode': False, 'dither': False, 'profile': 'x4', 'kinsoku_mode': 'standard', 'output_format': 'xtc'}}
        window.preset_combo = _ComboStub([], current_index=-1)
        window.preset_summary_label = _LabelStub()
        window.selected_preset_key = lambda: 'preset_1'
        window._refresh_preset_ui()
        self.assertEqual(window.preset_combo.items[0][0], 'プリセット1')
        summary_lines = window.preset_summary_label.text().splitlines()
        self.assertNotIn('プリセット1', window.preset_summary_label.text())
        self.assertTrue(summary_lines[0].startswith('機種: X4 / 出力形式: XTC'))
        self.assertIn('本文: 28', summary_lines[0])
        self.assertIn('フォント: font.ttf', window.preset_summary_label.text())
        self.assertNotIn('波線描画:', window.preset_summary_label.text())
        self.assertNotIn('波線位置:', window.preset_summary_label.text())
        self.assertNotIn('\n\n', window.preset_summary_label.text())
        self.assertNotIn('<div', window.preset_summary_label.text())
        self.assertNotIn('<span', window.preset_summary_label.text())

        window_multi = self.make_window()
