        window.on_font_changed = lambda _value: None
        window._refresh_preset_ui = lambda: None
        missing_profile_status = _StatusBarStub()
        window.statusBar = lambda: missing_profile_status

        window.apply_preset('preset_2')

        self.assertEqual(window.profile_combo.currentIndex(), -1)
        self.assertIsNone(window.profile_combo.currentData())
        self.assertEqual(window.current_profile_key, 'x4')
        self.assertEqual(window.viewer_widget.profile, self.studio.DEVICE_PROFILES['x4'])
        self.assertEqual(window.width_spin.value(), self.studio.DEVICE_PROFILES['x4'].width_px)
        self.assertEqual(window.height_spin.value(), self.studio.DEVICE_PROFILES['x4'].height_px)
        self.assertFalse(window.custom_size_row.visible)

        window = self.make_window()
        window.font_combo = _ComboStub([('Noto Sans Regular', 'Font/NotoSansJP-Regular.ttf')], current_index=0)
        self.assertEqual(window.current_font_value(), 'Font/NotoSansJP-Regular.ttf')
        with mock.patch.object(self.studio.core, 'get_font_entries', return_value=[
            {'label': 'MS Gothic', 'value': 'C:/Windows/MSGOTHIC.TTC'},
            {'label': 'Noto Sans Regular', 'value': 'Font/NotoSansJP-Regular.ttf'},
            {'label': 'Noto Sans Bold', 'value': 'Font/NotoSansJP-Bold.ttf'},
        ]):
            entries = window._available_font_entries()
        self.assertEqual([e['label'] for e in entries], ['Noto Sans Regular', 'Noto Sans Bold'])

        window.font_combo = _ComboStub([('Existing', 'font.ttf')], current_index=0)
        with mock.patch.object(self.studio.core, 'get_font_entries_for_value', return_value=[{'label': 'Added', 'value': 'added.ttf'}]),              mock.patch.object(self.studio.core, 'describe_font_value', return_value='Added'):
            window._ensure_font_combo_value('added.ttf')
        self.assertGreaterEqual(window.font_combo.findData('added.ttf'), 0)
        window._set_current_font_value('added.ttf')
        self.assertEqual(window.current_font_value(), 'added.ttf')

        with mock.patch.object(self.studio.core, 'get_font_entries_for_value', return_value=[]), \
             mock.patch.object(self.studio.core, 'describe_font_value', return_value='NotoSansJP-SemiBold.ttf'):
            window._ensure_font_combo_value('NotoSansJP-SemiBold.ttf')
        fallback_font_index = window.font_combo.findData('NotoSansJP-SemiBold.ttf')
        self.assertGreaterEqual(fallback_font_index, 0)
        fallback_font_label = window.font_combo.itemText(fallback_font_index)
        self.assertIn('NotoSansJP-SemiBold.ttf', fallback_font_label)

        with mock.patch.object(window, '_available_font_entries', return_value=[
            {'label': 'Noto Sans SemiBold', 'value': 'Font/NotoSansJP-SemiBold.ttf'},
            {'label': 'Other', 'value': 'other.ttf'},
        ]):
            self.assertEqual(window._default_font_name(), 'Font/NotoSansJP-SemiBold.ttf')
        chosen = []
        window._default_font_name = lambda: 'Font/NotoSansJP-SemiBold.ttf'
        window._set_current_font_value = lambda value: chosen.append(value)
        window._apply_default_font_selection()
        self.assertEqual(chosen, ['Font/NotoSansJP-SemiBold.ttf'])

