    def test_startup_preview_prompts_and_refreshes_previous_target_on_yes(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            target = Path(tmpdir) / 'current.txt'
            target.write_text('｜吾輩《わがはい》は猫である。', encoding='utf-8')
            window = self.make_window()
            calls = []
            question_calls = []
            window.target_edit = _LineEditStub(str(target))
            window.request_preview_refresh = lambda **kwargs: calls.append(kwargs) or True
            window._show_startup_sample_preview_status = lambda message: None
            window.save_ui_state = lambda: None

            def question(*args, **kwargs):
                question_calls.append(args)
                return 1

            with mock.patch.object(self.studio, 'QMessageBox', types.SimpleNamespace(question=question, Yes=1, No=0)):
                window._request_startup_preview_after_restore()

            self.assertEqual(calls, [{'reset_page': True}])
            self.assertTrue(question_calls)
            self.assertIn('前回の作業の続きを行いますか？', question_calls[0][2])
            self.assertEqual(window.target_edit.text(), str(target))

