    def test_target_preview_refresh_debounce_coalesces_pending_jobs(self):
        window = self.make_window()
        dirty_calls = []
        refresh_calls = []
        scheduled = []
        window.mark_preview_dirty_for_target_change = lambda: dirty_calls.append('target-dirty')
        window.mark_preview_dirty = lambda: dirty_calls.append('generic-dirty')
        window.request_preview_refresh = lambda **kwargs: refresh_calls.append(kwargs)

        with mock.patch.object(self.studio.QTimer, 'singleShot', side_effect=lambda delay, cb: scheduled.append((delay, cb)), create=True):
            window._schedule_target_preview_refresh(reset_page=True)
            window._schedule_target_preview_refresh(reset_page=False)

        self.assertEqual(dirty_calls, ['target-dirty', 'target-dirty'])
        self.assertEqual(refresh_calls, [])
        self.assertEqual(len(scheduled), 1)
        self.assertEqual(scheduled[0][0], 0)
        self.assertTrue(getattr(window, '_target_preview_refresh_scheduled', False))

        scheduled[0][1]()

        self.assertFalse(getattr(window, '_target_preview_refresh_scheduled', False))
        self.assertFalse(getattr(window, '_target_preview_refresh_pending_reset_page', False))
        self.assertEqual(refresh_calls, [{'reset_page': True}])

