    def test_xtg_blob_to_qimage_decodes_packed_bits_via_fast_path(self):
        blob = (
            b'XTG\x00'
            + (8).to_bytes(2, 'little')
            + (1).to_bytes(2, 'little')
            + bytes([0, 0])
            + (1).to_bytes(4, 'little')
            + (b'\x00' * 8)
            + bytes([0b10110010])
        )

        studio_xtc_io = importlib.import_module('tategakiXTC_gui_studio_xtc_io')
        with mock.patch.object(studio_xtc_io, '_pil_image_to_qimage', side_effect=lambda img: img) as pil_to_qimage:
            img = self.studio.xtg_blob_to_qimage(blob)

        self.assertEqual(img.mode, 'L')
        self.assertEqual(img.size, (8, 1))
        self.assertEqual(list(img.tobytes()), [255, 0, 255, 255, 0, 0, 255, 0])
        pil_to_qimage.assert_called_once()

    def test_xth_blob_to_qimage_decodes_expected_shades(self):
        blob = (
            b'XTH\x00'
            + (2).to_bytes(2, 'little')
            + (2).to_bytes(2, 'little')
            + bytes([0, 0])
            + (2).to_bytes(4, 'little')
            + (b'\x00' * 8)
            + bytes([0x50, 0xC0])
        )

        studio_xtc_io = importlib.import_module('tategakiXTC_gui_studio_xtc_io')
        with mock.patch.object(studio_xtc_io, '_pil_image_to_qimage', side_effect=lambda img: img) as pil_to_qimage:
            img = self.studio.xth_blob_to_qimage(blob)

        self.assertEqual(img.mode, 'L')
        self.assertEqual(img.size, (2, 2))
        self.assertEqual(list(img.tobytes()), [255, 85, 170, 0])
        pil_to_qimage.assert_called_once()


    def test_plan_value_helpers_normalize_string_scalars_and_tuples(self):
        window = self.make_window()

        self.assertEqual(window._plan_int_value({'spacing': '12'}, 'spacing', 4), 12)
        self.assertFalse(window._plan_bool_value({'trailing_stretch': 'false'}, 'trailing_stretch', True))
        self.assertEqual(
            window._plan_int_tuple_value({'contents_margins': ['1', 2, '3', 4]}, 'contents_margins', (0, 0, 0, 0), expected_length=4),
            (1, 2, 3, 4),
        )

    def test_plan_value_helpers_fallback_for_non_mapping_and_invalid_sequences(self):
        window = self.make_window()

        self.assertEqual(window._plan_int_value('bad-plan', 'spacing', 4), 4)
        self.assertTrue(window._plan_bool_value('bad-plan', 'enabled', True))
        self.assertEqual(
            window._plan_int_tuple_value({'contents_margins': '1,2,3,4'}, 'contents_margins', (9, 8, 7, 6), expected_length=4),
            (9, 8, 7, 6),
        )
        self.assertEqual(
            window._plan_int_tuple_value({'contents_margins': [1, 'x', 3, 4]}, 'contents_margins', (9, 8, 7, 6), expected_length=4),
            (9, 8, 7, 6),
        )

