    def test_load_xtc_from_path_failure_reuses_status_when_critical_dialog_raises(self):
        window = self.make_window()
        window.main_view_mode = 'device'
        window.viewer_widget = _ViewerWidgetStub()
        window.current_xtc_label = _LabelStub()
        window.current_xtc_label.setText('表示中: old.xtc')
        window._loaded_xtc_path_text = 'old.xtc'
        window._loaded_xtc_display_name = 'old.xtc'
        item_old = _ListWidgetItemDataStub('old.xtc')
        item_broken = _ListWidgetItemDataStub('broken.xtc')
        window.results_list = _ListWidgetStub([item_old, item_broken])
        window.results_list.setCurrentItem(item_broken)
        window.progress_label = _LabelStub()
        window.log_edit = _TextAppendStub()
        status = _StatusBarStub()
        window.statusBar = lambda: status
        window.worker = None

        with mock.patch.object(self.studio.QMessageBox, 'critical', side_effect=RuntimeError('dialog boom'), create=True),              mock.patch.object(Path, 'read_bytes', side_effect=RuntimeError('bad file')):
            window.load_xtc_from_path('broken.xtc')

        self.assertEqual(
            status.messages[-1],
            ('XTC/XTCH読込失敗: broken.xtc（表示は old.xtc のまま） / bad file', 5000),
        )
        self.assertEqual(window.progress_label.text(), 'XTC/XTCH読込失敗: broken.xtc（表示は old.xtc のまま） / bad file')
        self.assertEqual(window.log_edit.lines[-1], 'XTC/XTCH読込失敗: broken.xtc（表示は old.xtc のまま） / bad file')

