        window.statusBar = lambda: status
        window.bottom_tabs = _StackStub()
        show_calls = []

        def _show_results(converted_files, summary_lines):
            show_calls.append((list(converted_files), list(summary_lines or [])))
            window._set_bottom_tab_index_with_fallback(self.studio.LOG_TAB_INDEX)

        window._show_conversion_results = _show_results
        window.on_conversion_finished({'message': 'done', 'converted_files': ['exports/book.xtc'], 'summary_lines': ['保存 1 件'], 'stopped': False})

        self.assertEqual(show_calls, [(['exports/book.xtc'], ['保存 1 件'])])
